import React, { useState } from "react";
import { api } from "../../api";
import "./LoginPage.css"; 

const LoginPage = ({ onSuccess, onNavigate }) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const data = await api.login({ email, password });
      if (data && data.accessToken) {
        // Передаем данные в App.js
        onSuccess(data.accessToken, data.user);
      }
    } catch (err) {
      alert(err.response?.data?.error || "Ошибка соединения с сервером");
    }
  };

  return (
    <div className="login-container">
      <div className="login-box">
        <h2 className="login-title">Вход</h2>
        
        <form className="login-form" onSubmit={handleSubmit}> 
          <input
            className="login-input"
            type="email"
            placeholder="Электронная почта"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          
          <input
            className="login-input"
            type="password"
            placeholder="Пароль"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />

          <button className="login-button" type="submit">
            Войти
          </button>
        </form>

        <div className="login-links">
          <p>Нет аккаунта?</p>
          <button className="register-link" onClick={onNavigate}>
            Зарегистрироваться
          </button>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
